/*
 * bench_generated.c — Benchmark the ACTUAL code generated by AMO-Lean's e-graph
 *
 * This file #includes the C files generated by Lean's UnifiedCodeGen,
 * then benchmarks them against a Plonky3-style scalar Montgomery baseline.
 *
 * The generated files were produced by:
 *   lake env lean --run tests/egraph_end_to_end.lean
 * Which runs: selectConfig → generateNTT → writeAllTargets
 *
 * Compile: cc -O2 -o bench_generated bench_generated.c
 * Run:     ./bench_generated
 */

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <time.h>
#include <arm_neon.h>

#define BABYBEAR_P  0x78000001U
#define BABYBEAR_MU 0x88000001U

/* ═══════════════════════════════════════════════════════════════════
   Include the code GENERATED BY LEAN (via e-graph cost model)
   These files were written by UnifiedCodeGen.writeAllTargets
   ═══════════════════════════════════════════════════════════════════ */

/* Rename to avoid conflicts */
#define butterfly bf_scalar_generated
#define ntt_scalar_arm ntt_scalar_generated
#include "../../generated/unified/ntt_scalar_arm.c"
#undef butterfly
#undef ntt_scalar_arm

#define butterfly bf_neon_generated
#define ntt_simd_neon ntt_neon_generated
#include "../../generated/unified/ntt_simd_neon.c"
#undef butterfly
#undef ntt_simd_neon

/* ═══════════════════════════════════════════════════════════════════
   Plonky3 scalar Montgomery (reference baseline, NOT generated)
   ═══════════════════════════════════════════════════════════════════ */

static inline uint32_t p3_reduce(uint64_t x) {
    uint64_t t = (x * (uint64_t)BABYBEAR_MU) & 0xFFFFFFFF;
    uint64_t u = t * (uint64_t)BABYBEAR_P;
    uint64_t d = x - u;
    uint32_t hi = (uint32_t)(d >> 32);
    return (x < u) ? hi + BABYBEAR_P : hi;
}

static inline void p3_butterfly(uint32_t *a, uint32_t *b, uint32_t w) {
    uint32_t oa = *a;
    uint32_t wb = p3_reduce((uint64_t)w * (uint64_t)(*b));
    uint32_t sum = oa + wb;
    if (sum >= BABYBEAR_P) sum -= BABYBEAR_P;
    *a = sum;
    *b = (oa >= wb) ? oa - wb : BABYBEAR_P - wb + oa;
}

static void ntt_plonky3(uint32_t *data, size_t n, const uint32_t *tw) {
    size_t log_n = 0;
    for (size_t t = n; t > 1; t >>= 1) log_n++;
    for (size_t s = 0; s < log_n; s++) {
        size_t half = 1 << (log_n - s - 1);
        for (size_t g = 0; g < (1u << s); g++)
            for (size_t p = 0; p < half; p++) {
                size_t i = g * 2 * half + p, j = i + half;
                p3_butterfly(&data[i], &data[j], tw[s*(n/2)+g*half+p]);
            }
    }
}

/* ═══════════════════════════════════════════════════════════════════
   Benchmark
   ═══════════════════════════════════════════════════════════════════ */

typedef struct { const char *name; double us; } R;

static R bench_u32(const char *name, size_t n, int iters,
    void (*ntt)(uint32_t*, size_t, const uint32_t*)) {
    uint32_t *data = malloc(n * sizeof(uint32_t));
    uint32_t *tw = malloc(n * sizeof(uint32_t));
    for (size_t i = 0; i < n; i++) tw[i] = (uint32_t)((i * 7 + 31) % BABYBEAR_P);
    struct timespec start, end;
    clock_gettime(CLOCK_MONOTONIC, &start);
    for (int it = 0; it < iters; it++) {
        for (size_t i = 0; i < n; i++) data[i] = (uint32_t)((i * 1000000007ULL) % BABYBEAR_P);
        ntt(data, n, tw);
    }
    clock_gettime(CLOCK_MONOTONIC, &end);
    double el = (end.tv_sec - start.tv_sec) + (end.tv_nsec - start.tv_nsec) / 1e9;
    double us = el / iters * 1e6;
    printf("  %-45s: %8.1f us  %6.1f Melem/s\n", name, us, (double)n*iters/el/1e6);
    free(data); free(tw);
    return (R){name, us};
}

static R bench_s32(const char *name, size_t n, int iters,
    void (*ntt)(int32_t*, size_t, const int32_t*)) {
    int32_t *data = malloc(n * sizeof(int32_t));
    int32_t *tw = malloc(n * sizeof(int32_t));
    for (size_t i = 0; i < n; i++) tw[i] = (int32_t)((i * 7 + 31) % BABYBEAR_P);
    struct timespec start, end;
    clock_gettime(CLOCK_MONOTONIC, &start);
    for (int it = 0; it < iters; it++) {
        for (size_t i = 0; i < n; i++) data[i] = (int32_t)((i * 1000000007ULL) % BABYBEAR_P);
        ntt(data, n, tw);
    }
    clock_gettime(CLOCK_MONOTONIC, &end);
    double el = (end.tv_sec - start.tv_sec) + (end.tv_nsec - start.tv_nsec) / 1e9;
    double us = el / iters * 1e6;
    printf("  %-45s: %8.1f us  %6.1f Melem/s\n", name, us, (double)n*iters/el/1e6);
    free(data); free(tw);
    return (R){name, us};
}

int main(void) {
    printf("╔══════════════════════════════════════════════════════════════════════════╗\n");
    printf("║  END-TO-END: Code Generated by AMO-Lean E-Graph vs Plonky3 Scalar     ║\n");
    printf("╠══════════════════════════════════════════════════════════════════════════╣\n");
    printf("║  Scalar code: generated by selectConfig(arm_cortex_a76) → solinasFold ║\n");
    printf("║  NEON code:   generated by selectConfig(arm_neon_simd) → montgomery   ║\n");
    printf("║  Plonky3:     hand-written scalar Montgomery (reference)              ║\n");
    printf("║  NOTHING hardcoded — all code generated from Lean via e-graph         ║\n");
    printf("╚══════════════════════════════════════════════════════════════════════════╝\n\n");

    size_t sizes[] = {1024, 4096, 16384};
    int iters[] = {5000, 1000, 200};

    for (int si = 0; si < 3; si++) {
        size_t n = sizes[si];
        int it = iters[si];
        printf("══ BabyBear N = %zu ══\n\n", n);

        R r_p3 = bench_u32("Plonky3 scalar Montgomery (reference)", n, it, ntt_plonky3);
        R r_gen_scalar = bench_u32("AMO-Lean GENERATED scalar (Solinas fold)", n, it, ntt_scalar_generated);
        R r_gen_neon = bench_s32("AMO-Lean GENERATED NEON (Montgomery)", n, it, ntt_neon_generated);

        printf("\n");
        printf("  Generated scalar vs Plonky3:  %+.1f%%\n", (1.0 - r_gen_scalar.us/r_p3.us)*100);
        printf("  Generated NEON vs Plonky3:    %+.1f%%\n", (1.0 - r_gen_neon.us/r_p3.us)*100);
        printf("\n");
    }

    printf("Pipeline:\n");
    printf("  1. E-graph saturates reduceGate with 4 alternatives\n");
    printf("  2. Cost model (isSimd, wideningPenalty) selects strategy\n");
    printf("  3. UnifiedCodeGen.generateNTT emits C with chosen strategy\n");
    printf("  4. This benchmark compiles and runs that generated C\n");
    printf("  5. Verification: solinasFold_mod_correct / montyReduce = x %% p\n");
    return 0;
}
